import mysql.connector
import os
import re
from pathlib import Path

class SecureDataImporter:
    def __init__(self, host, user, password, database):
        self.host = host
        self.user = user
        self.password = password
        self.database = database
        self.connection = None
        self.cursor = None
        
    def connect(self):
        self.connection = mysql.connector.connect(
            host=self.host,
            user=self.user,
            password=self.password,
            database=self.database,
            allow_local_infile=True
        )
        self.cursor = self.connection.cursor()
        
    def disconnect(self):
        if self.cursor:
            self.cursor.close()
        if self.connection:
            self.connection.close()
    
    def validate_file_path(self, file_path):
        try:
            path = Path(file_path).resolve()
            
            if not path.exists():
                raise ValueError(f"File does not exist: {file_path}")
            
            if not path.is_file():
                raise ValueError(f"Path is not a file: {file_path}")
            
            allowed_extensions = {'.csv', '.txt', '.tsv', '.dat'}
            if path.suffix.lower() not in allowed_extensions:
                raise ValueError(f"File type not allowed. Allowed types: {allowed_extensions}")
            
            if path.stat().st_size > 1024 * 1024 * 1024:
                raise ValueError("File size exceeds 1GB limit")
            
            return str(path)
        except Exception as e:
            raise ValueError(f"Invalid file path: {e}")
    
    def validate_table_name(self, table_name):
        if not re.match(r'^[a-zA-Z0-9_]+$', table_name):
            raise ValueError("Invalid table name. Only alphanumeric characters and underscores allowed.")
        return table_name
    
    def validate_column_names(self, columns):
        if not columns:
            return None
        
        validated_columns = []
        for col in columns:
            if not re.match(r'^[a-zA-Z0-9_]+$', col):
                raise ValueError(f"Invalid column name: {col}. Only alphanumeric characters and underscores allowed.")
            validated_columns.append(col)
        return validated_columns
    
    def load_data(self, file_path, table_name, columns=None, field_delimiter=',', 
                  line_terminator='\\n', ignore_lines=0, enclosed_by=None):
        try:
            validated_path = self.validate_file_path(file_path)
            validated_table = self.validate_table_name(table_name)
            validated_columns = self.validate_column_names(columns) if columns else None
            
            escaped_path = validated_path.replace('\\', '\\\\')
            
            query = f"LOAD DATA LOCAL INFILE %s INTO TABLE `{validated_table}`"
            
            query += f" FIELDS TERMINATED BY %s"
            
            if enclosed_by:
                query += f" ENCLOSED BY %s"
            
            query += f" LINES TERMINATED BY %s"
            
            if ignore_lines > 0:
                query += f" IGNORE {int(ignore_lines)} LINES"
            
            if validated_columns:
                columns_str = ', '.join([f"`{col}`" for col in validated_columns])
                query += f" ({columns_str})"
            
            params = [escaped_path, field_delimiter]
            if enclosed_by:
                params.append(enclosed_by)
            params.append(line_terminator)
            
            self.cursor.execute(query, params)
            self.connection.commit()
            
            rows_affected = self.cursor.rowcount
            print(f"Successfully imported {rows_affected} rows into {validated_table}")
            return rows_affected
            
        except mysql.connector.Error as err:
            self.connection.rollback()
            print(f"MySQL Error: {err}")
            raise
        except Exception as e:
            self.connection.rollback()
            print(f"Error: {e}")
            raise
    
    def get_table_info(self, table_name):
        validated_table = self.validate_table_name(table_name)
        query = "DESCRIBE `{}`".format(validated_table)
        self.cursor.execute(query)
        return self.cursor.fetchall()


